import{_ as a,o as i,c as t,am as o}from"./chunks/framework.Bzrn_8o_.js";const h=JSON.parse('{"title":"Tutorials Overview","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/overview.md","filePath":"tutorials/overview.md","lastUpdated":null}'),r={name:"tutorials/overview.md"};function n(s,e,l,d,p,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="Tutorials-Overview" tabindex="-1">Tutorials Overview <a class="header-anchor" href="#Tutorials-Overview" aria-label="Permalink to &quot;Tutorials Overview {#Tutorials-Overview}&quot;">​</a></h1><p>Welcome to the EasyHybrid.jl tutorials! This section provides comprehensive guides and examples to help you get started with hybrid modeling—combining process-based models with neural networks.</p><h2 id="Getting-Started" tabindex="-1">Getting Started <a class="header-anchor" href="#Getting-Started" aria-label="Permalink to &quot;Getting Started {#Getting-Started}&quot;">​</a></h2><p>If you&#39;re new to EasyHybrid.jl, we recommend starting with the <a href="./../get_started">Getting Started</a> guide, which walks through building your first hybrid model step by step.</p><h2 id="Tutorial-Topics" tabindex="-1">Tutorial Topics <a class="header-anchor" href="#Tutorial-Topics" aria-label="Permalink to &quot;Tutorial Topics {#Tutorial-Topics}&quot;">​</a></h2><h3 id="Core-Tutorials" tabindex="-1">Core Tutorials <a class="header-anchor" href="#Core-Tutorials" aria-label="Permalink to &quot;Core Tutorials {#Core-Tutorials}&quot;">​</a></h3><h4 id="Exponential-Respiration-Modelexponential_res.md" tabindex="-1"><a href="./exponential_res">Exponential Respiration Model</a> <a class="header-anchor" href="#Exponential-Respiration-Modelexponential_res.md" aria-label="Permalink to &quot;[Exponential Respiration Model](exponential_res.md) {#Exponential-Respiration-Modelexponential_res.md}&quot;">​</a></h4><p>Learn to build a hybrid model for soil respiration using an exponential temperature relationship. This tutorial demonstrates:</p><ul><li><p>Creating synthetic data with exponential temperature response</p></li><li><p>Defining a process-based model (<code>Expo_resp_model</code>)</p></li><li><p>Configuring model parameters and constructing hybrid models</p></li><li><p>Training and evaluating your model</p></li></ul><p><strong>Best for</strong>: Understanding the fundamentals of hybrid modeling with a simple, well-documented example.</p><h4 id="LSTM-Hybrid-Modelexample_synthetic_lstm.md" tabindex="-1"><a href="./example_synthetic_lstm">LSTM Hybrid Model</a> <a class="header-anchor" href="#LSTM-Hybrid-Modelexample_synthetic_lstm.md" aria-label="Permalink to &quot;[LSTM Hybrid Model](example_synthetic_lstm.md) {#LSTM-Hybrid-Modelexample_synthetic_lstm.md}&quot;">​</a></h4><p>Explore advanced neural network architectures by building a hybrid model with LSTM (Long Short-Term Memory) networks. This tutorial covers:</p><ul><li><p>Using LSTM networks for sequence modeling</p></li><li><p>Configuring feedforward vs. recurrent architectures</p></li><li><p>Working with sequence data (input/output windows, lead times)</p></li><li><p>Comparing LSTM and standard neural network performance</p></li></ul><p><strong>Best for</strong>: Working with time series data that requires memory of past states.</p><h3 id="Model-Evaluation-and-Optimization" tabindex="-1">Model Evaluation and Optimization <a class="header-anchor" href="#Model-Evaluation-and-Optimization" aria-label="Permalink to &quot;Model Evaluation and Optimization {#Model-Evaluation-and-Optimization}&quot;">​</a></h3><h4 id="Cross-Validationfolds.md" tabindex="-1"><a href="./folds">Cross-Validation</a> <a class="header-anchor" href="#Cross-Validationfolds.md" aria-label="Permalink to &quot;[Cross-Validation](folds.md) {#Cross-Validationfolds.md}&quot;">​</a></h4><p>Implement k-fold cross-validation to robustly evaluate your hybrid models. Learn how to:</p><ul><li><p>Create and manage data folds</p></li><li><p>Train models across multiple validation splits</p></li><li><p>Parallelize cross-validation training</p></li><li><p>Organize results from multiple model runs</p></li></ul><p><strong>Best for</strong>: Ensuring your model generalizes well and avoiding overfitting.</p><h4 id="Hyperparameter-Tuninghyperparameter_tuning.md" tabindex="-1"><a href="./hyperparameter_tuning">Hyperparameter Tuning</a> <a class="header-anchor" href="#Hyperparameter-Tuninghyperparameter_tuning.md" aria-label="Permalink to &quot;[Hyperparameter Tuning](hyperparameter_tuning.md) {#Hyperparameter-Tuninghyperparameter_tuning.md}&quot;">​</a></h4><p>Optimize your model&#39;s performance using Hyperopt.jl for automated hyperparameter search. This tutorial shows:</p><ul><li><p>Setting up hyperparameter search spaces</p></li><li><p>Using the <code>tune</code> function for optimization</p></li><li><p>Comparing model performance before and after tuning</p></li><li><p>Best practices for hyperparameter selection</p></li></ul><p><strong>Best for</strong>: Finding optimal model configurations and improving performance.</p><h3 id="Advanced-Topics" tabindex="-1">Advanced Topics <a class="header-anchor" href="#Advanced-Topics" aria-label="Permalink to &quot;Advanced Topics {#Advanced-Topics}&quot;">​</a></h3><h4 id="Losses-and-LoggingLosslosses.md" tabindex="-1"><a href="./losses">Losses and LoggingLoss</a> <a class="header-anchor" href="#Losses-and-LoggingLosslosses.md" aria-label="Permalink to &quot;[Losses and LoggingLoss](losses.md) {#Losses-and-LoggingLosslosses.md}&quot;">​</a></h4><p>Deep dive into the loss function system in EasyHybrid.jl. Learn about:</p><ul><li><p>Predefined loss functions (MSE, MAE, NSE)</p></li><li><p>Creating custom loss functions</p></li><li><p>Handling missing values and uncertainty</p></li><li><p>Using <code>LoggingLoss</code> for training and evaluation</p></li><li><p>Passing additional arguments and keyword arguments to losses</p></li></ul><p><strong>Best for</strong>: Customizing model training and implementing domain-specific loss functions.</p><h4 id="Slurm-Jobsslurm.md" tabindex="-1"><a href="./slurm">Slurm Jobs</a> <a class="header-anchor" href="#Slurm-Jobsslurm.md" aria-label="Permalink to &quot;[Slurm Jobs](slurm.md) {#Slurm-Jobsslurm.md}&quot;">​</a></h4><p>Run EasyHybrid.jl models on HPC clusters using Slurm job scheduling. This tutorial provides:</p><ul><li><p>Example Slurm batch scripts</p></li><li><p>Configuring Julia for cluster environments</p></li><li><p>Running array jobs for parallel experiments</p></li><li><p>Resource allocation best practices</p></li></ul><p><strong>Best for</strong>: Scaling up training to high-performance computing environments.</p><h2 id="Choosing-the-Right-Tutorial" tabindex="-1">Choosing the Right Tutorial <a class="header-anchor" href="#Choosing-the-Right-Tutorial" aria-label="Permalink to &quot;Choosing the Right Tutorial {#Choosing-the-Right-Tutorial}&quot;">​</a></h2><ul><li><p><strong>New to EasyHybrid?</strong> → Start with <a href="./exponential_res">Exponential Respiration Model</a></p></li><li><p><strong>Working with time series?</strong> → Check out <a href="./example_synthetic_lstm">LSTM Hybrid Model</a></p></li><li><p><strong>Need robust evaluation?</strong> → See <a href="./folds">Cross-Validation</a></p></li><li><p><strong>Want to optimize performance?</strong> → Try <a href="./hyperparameter_tuning">Hyperparameter Tuning</a></p></li><li><p><strong>Customizing training?</strong> → Read <a href="./losses">Losses and LoggingLoss</a></p></li><li><p><strong>Running on clusters?</strong> → Follow <a href="./slurm">Slurm Jobs</a></p></li></ul><h2 id="Next-Steps" tabindex="-1">Next Steps <a class="header-anchor" href="#Next-Steps" aria-label="Permalink to &quot;Next Steps {#Next-Steps}&quot;">​</a></h2><p>After completing the tutorials, explore the <a href="./../research/overview">Research</a> section to see real-world applications, or dive into the <a href="./../api">API Reference</a> for detailed function documentation.</p>',36)])])}const g=a(r,[["render",n]]);export{h as __pageData,g as default};
